(1, 'Đề thi thử HSK 1 - Số 1', 'hsk', 1, 40, '[{"type":"single","section":"Phần 1: Từ vựng HSK1","q":"\"小时\" (xiǎoshí) có nghĩa là gì?","options":["some","piece","hour","bread"],"answer":2,"explain":"小时 (xiǎoshí) = hour. Loại từ: n."},{"type":"single","section":"Phần 3: Đọc hiểu HSK1","q":"Đoạn văn sau có nghĩa là gì? \"它们来问。\"","options":["Câu hỏi về (plural of 它) they; them; their","Không hiểu nghĩa của 问","Câu phủ định về (plural of 它) they; them; their","(plural of 它) they; them; their come ask."],"answer":3,"explain":"Câu \"它们来问。\" có nghĩa là: (plural of 它) they; them; their come ask."},{"type":"single","section":"Phần 2: Ngữ pháp HSK1","q":"Chọn từ/cụm từ đúng để hoàn thành câu: \"我可以再问您一个问题吗？ _____ có thể hỏi cô thêm một câu được không?)\"","options":["可以 + 动词吗","可以 + 动词了","词动 + 以可","可以 + 动词"],"answer":3,"explain":"Tôi có thể hỏi cô thêm một câu được không? Ví dụ: 我可以再问您一个问题吗？ (Tôi có thể hỏi cô thêm một câu được không?)"},{"type":"single","section":"Phần 1: Từ vựng HSK1","q":"\"在\" (zài) có nghĩa là gì?","options":["in the process of","indicating locality/edge; side","male; man","at/in"],"answer":3,"explain":"在 (zài) = at/in. Loại từ: prep."},{"type":"single","section":"Phần 1: Từ vựng HSK1","q":"\"面包\" (miànbāo) có nghĩa là gì?","options":["which","bread","dinner; supper","classmate"],"answer":1,"explain":"面包 (miànbāo) = bread. Loại từ: n."},{"type":"single","section":"Phần 4: Nghe hiểu HSK1","q":"Bạn nghe thấy: \"xiǎopéngyǒu\". Đó là chữ Hán nào?","options":["for certain animals","child; kid","really; truly","water"],"answer":1,"explain":"\"小朋友\" (xiǎopéngyǒu) có nghĩa là: child; kid"},{"type":"single","section":"Phần 1: Từ vựng HSK1","q":"\"知道\" (zhīdào) có nghĩa là gì?","options":["that''s all right; never mind","know; realize","need; take","today"],"answer":1,"explain":"知道 (zhīdào) = know; realize. Loại từ: v."},{"type":"single","section":"Phần 2: Ngữ pháp HSK1","q":"Chọn từ/cụm từ đúng để hoàn thành câu: \"二十二，九百九十九 _____ 999)\"","options":["0–99, 百, 千, 万吗","0–99, 百, 千, 万了","万 ,千 ,百 ,99–0","0–99, 百, 千, 万"],"answer":3,"explain":"22, 999 Ví dụ: 二十二，九百九十九 (22, 999)"},{"type":"single","section":"Phần 4: Nghe hiểu HSK1","q":"Bạn nghe thấy: \"yī\". Đó là chữ Hán nào?","options":["dish; course","go to work","(referring to female people) they; them","medicine"],"answer":3,"explain":"\"医\" (yī) có nghĩa là: medicine"},{"type":"single","section":"Phần 2: Ngữ pháp HSK1","q":"Chọn từ/cụm từ đúng để hoàn thành câu: \"上课 _____ 上了课；睡觉 → 睡了一觉 (Lên lớp → đã lên lớp; ngủ → đã ngủ một giấc)\"","options":["合可分可","可分可合","可分可合了","可分可合吗"],"answer":1,"explain":"Lên lớp → đã lên lớp; ngủ → đã ngủ một giấc Ví dụ: 上课 → 上了课；睡觉 → 睡了一觉 (Lên lớp → đã lên lớp; ngủ → đã ngủ một giấc)"},{"type":"single","section":"Phần 1: Từ vựng HSK1","q":"\"冷\" (lěng) có nghĩa là gì?","options":["hot; warm","cold","minute","want; wish"],"answer":1,"explain":"冷 (lěng) = cold. Loại từ: adj."},{"type":"single","section":"Phần 1: Từ vựng HSK1","q":"\"看见\" (kànjiàn) có nghĩa là gì?","options":["too; excessively","cup; glass","see; catch sight of","(early) morning"],"answer":2,"explain":"看见 (kànjiàn) = see; catch sight of. Loại từ: v."},{"type":"single","section":"Phần 3: Đọc hiểu HSK1","q":"Câu \"电话哪没关系。\" diễn đạt điều gì?","options":["Câu hỏi về telephone (set); (telephone/phone) call","Không hiểu nghĩa của 没关系","Câu phủ định về telephone (set); (telephone/phone) call","telephone (set); (telephone/phone) call which that''s all right; never mind."],"answer":3,"explain":"Câu \"电话哪没关系。\" có nghĩa là: telephone (set); (telephone/phone) call which that''s all right; never mind."},{"type":"single","section":"Phần 1: Từ vựng HSK1","q":"\"想\" (xiǎng) có nghĩa là gì?","options":["where","weather","miss","year"],"answer":2,"explain":"想 (xiǎng) = miss. Loại từ: v."},{"type":"single","section":"Phần 2: Ngữ pháp HSK1","q":"Chọn từ/cụm từ đúng để hoàn thành câu: \"白家月的中文老师 _____ viên tiếng Trung của Bạch Gia Nguyệt)\"","options":["定语 + 的 + 中心语了","语心中 + 的 + 语定","定语 +  + 中心语","定